    static func isSet(_ kind: WeatherIconKind, x: Int, y: Int) -> Bool {
        let offset = kind.rawValue * bytesPerIcon + y * rowBytes + x / 8
        return bytes[offset] & (0x80 >> UInt8(x % 8)) != 0
    }
